// SPDX-License-Identifier: MIT

pragma solidity >=0.8.8;

import {Field} from "./Field.sol";

// Poseidon2 hash function
// credits: https://github.com/noir-lang/noir/blob/d8710c4442be2fcffc348f1f5776bc278d028ad0/acvm-repo/bn254_blackbox_solver/src/poseidon2.rs
library LibPoseidon2 {
    using Field for *;
    using LibPoseidon2 for Sponge;

    uint256 constant t = 4;
    uint256 constant rounds_f = 8;
    uint256 constant rounds_p = 56;
    uint256 constant RATE = 3;

    struct Constants {
        Field.Type[4] internal_matrix_diagonal;
        Field.Type[4][64] round_constant;
    }

    struct Sponge {
        Field.Type iv;
        Field.Type[3] cache;
        Field.Type[4] state;
        uint256 cache_size;
        bool squeeze_mode; // 0 => absorb, 1 => squeeze
        Constants constants;
    }

    /**
     * Public API: best for single time use
     */
    function hash_1(Field.Type m) internal pure returns (Field.Type) {
        Field.Type[] memory inputs = new Field.Type[](1);
        inputs[0] = m;
        return hash_internal(load(), inputs, 1, false);
    }

    function hash_2(Field.Type m1, Field.Type m2) internal pure returns (Field.Type) {
        Field.Type[] memory inputs = new Field.Type[](2);
        inputs[0] = m1;
        inputs[1] = m2;
        return hash_internal(load(), inputs, 2, false);
    }

    function hash_3(Field.Type m1, Field.Type m2, Field.Type m3) internal pure returns (Field.Type) {
        Field.Type[] memory inputs = new Field.Type[](3);
        inputs[0] = m1;
        inputs[1] = m2;
        inputs[2] = m3;
        return hash_internal(load(), inputs, 3, false);
    }

    function hash(Field.Type[] memory inputs, uint256 std_input_length, bool is_variable_length)
        internal
        pure
        returns (Field.Type)
    {
        return hash_internal(load(), inputs, std_input_length, is_variable_length);
    }

    /**
     * Public API: best for multiple use in same call context
     */
    function hash_1(LibPoseidon2.Constants memory constants, Field.Type m) internal pure returns (Field.Type) {
        Field.Type[] memory inputs = new Field.Type[](1);
        inputs[0] = m;
        return hash_internal(constants, inputs, 1, false);
    }

    function hash_2(LibPoseidon2.Constants memory constants, Field.Type m1, Field.Type m2)
        internal
        pure
        returns (Field.Type)
    {
        Field.Type[] memory inputs = new Field.Type[](2);
        inputs[0] = m1;
        inputs[1] = m2;
        return hash_internal(constants, inputs, 2, false);
    }

    function hash_3(LibPoseidon2.Constants memory constants, Field.Type m1, Field.Type m2, Field.Type m3)
        internal
        pure
        returns (Field.Type)
    {
        Field.Type[] memory inputs = new Field.Type[](3);
        inputs[0] = m1;
        inputs[1] = m2;
        inputs[2] = m3;
        return hash_internal(constants, inputs, 3, false);
    }

    /**
     * Internal methods for hashing
     */
    function generate_iv(uint256 input_length) internal pure returns (Field.Type) {
        return Field.Type.wrap(input_length << 64);
    }

    function hash_internal(
        LibPoseidon2.Constants memory constants,
        Field.Type[] memory input,
        uint256 std_input_length,
        bool is_variable_length
    ) internal pure returns (Field.Type) {
        LibPoseidon2.Sponge memory sponge = new_poseidon2(generate_iv(input.length), constants);

        for (uint256 i; i < input.length; i++) {
            if (i < std_input_length) {
                sponge.absorb(input[i]);
            }
        }

        // In the case where the hash preimage is variable-length, we append `1` to the end of the input, to distinguish
        // from fixed-length hashes. (the combination of this additional field element + the hash IV ensures
        // fixed-length and variable-length hashes do not collide)
        if (is_variable_length) {
            sponge.absorb(Field.Type.wrap(1));
        }
        return sponge.squeeze();
    }

    function new_poseidon2(Field.Type iv, Constants memory constants)
        private
        pure
        returns (LibPoseidon2.Sponge memory)
    {
        LibPoseidon2.Sponge memory result = LibPoseidon2.Sponge({
            iv: iv,
            cache: [Field.Type.wrap(0), Field.Type.wrap(0), Field.Type.wrap(0)],
            state: [Field.Type.wrap(0), Field.Type.wrap(0), Field.Type.wrap(0), Field.Type.wrap(0)],
            cache_size: 0,
            squeeze_mode: false,
            constants: constants
        });
        result.state[RATE] = iv;
        return result;
    }

    function perform_duplex(LibPoseidon2.Sponge memory self) internal pure returns (Field.Type[RATE] memory) {
        // zero-pad the cache
        for (uint256 i; i < RATE; i++) {
            if (i >= self.cache_size) {
                self.cache[i] = Field.Type.wrap(0);
            }
        }

        // add the cache into sponge state
        for (uint256 i; i < RATE; i++) {
            self.state[i] = self.state[i].add(self.cache[i]);
        }
        self.state = permutation(self.state, self.constants.internal_matrix_diagonal, self.constants.round_constant);
        // return `RATE` number of field elements from the sponge state.
        Field.Type[RATE] memory result = [Field.Type.wrap(0), Field.Type.wrap(0), Field.Type.wrap(0)];
        for (uint256 i; i < RATE; i++) {
            result[i] = self.state[i];
        }
        return result;
    }

    function absorb(LibPoseidon2.Sponge memory self, Field.Type input) internal pure {
        if ((!self.squeeze_mode) && (self.cache_size == RATE)) {
            // If we're absorbing, and the cache is full, apply the sponge permutation to compress the cache
            self.perform_duplex();
            self.cache[0] = input;
            self.cache_size = 1;
        } else if ((!self.squeeze_mode) && (self.cache_size != RATE)) {
            // If we're absorbing, and the cache is not full, add the input into the cache
            self.cache[self.cache_size] = input;
            self.cache_size += 1;
        }
    }

    function squeeze(LibPoseidon2.Sponge memory self) internal pure returns (Field.Type) {
        if (!self.squeeze_mode) {
            // If we're in absorb mode, apply sponge permutation to compress the cache, populate cache with compressed
            // state and switch to squeeze mode. Note: this code block will execute if the previous `if` condition was
            // matched
            Field.Type[RATE] memory new_output_elements = self.perform_duplex();
            self.squeeze_mode = true;
            for (uint256 i; i < RATE; i++) {
                self.cache[i] = new_output_elements[i];
            }
            self.cache_size = RATE;
        }
        // By this point, we should have a non-empty cache. Pop one item off the top of the cache and return it.
        Field.Type result = self.cache[0];
        for (uint256 i = 1; i < RATE; i++) {
            if (i < self.cache_size) {
                self.cache[i - 1] = self.cache[i];
            }
        }

        self.cache_size -= 1;
        self.cache[self.cache_size] = Field.Type.wrap(0);
        return result;
    }

    function permutation(
        Field.Type[4] memory inputs,
        Field.Type[4] memory internal_matrix_diagonal,
        Field.Type[4][64] memory round_constant
    ) private pure returns (Field.Type[4] memory) {
        // Read witness assignments
        Field.Type[4] memory state = [Field.Type.wrap(0), Field.Type.wrap(0), Field.Type.wrap(0), Field.Type.wrap(0)];
        for (uint256 i; i < 4; i++) {
            state[i] = inputs[i];
        }

        // Apply 1st linear layer
        matrix_multiplication_4x4(state);

        // First set of external rounds
        uint256 rf_first = rounds_f / 2;
        for (uint256 r; r < rf_first; r++) {
            add_round_constants(state, round_constant, r);
            s_box(state);
            matrix_multiplication_4x4(state);
        }

        // Internal rounds
        uint256 p_end = rf_first + rounds_p;
        for (uint256 r = rf_first; r < p_end; r++) {
            state[0] = state[0].add(round_constant[r][0]);
            state[0] = single_box(state[0]);
            internal_m_multiplication(state, internal_matrix_diagonal);
        }

        // Remaining external rounds
        uint256 num_rounds = rounds_f + rounds_p;

        for (uint256 r = p_end; r < num_rounds; r++) {
            add_round_constants(state, round_constant, r);
            s_box(state);
            matrix_multiplication_4x4(state);
        }

        return state;
    }

    function single_box(Field.Type x) private pure returns (Field.Type) {
        Field.Type s = x.mul(x);
        return s.mul(s).mul(x);
    }

    function s_box(Field.Type[4] memory input) private pure {
        for (uint256 i; i < 4; i++) {
            input[i] = single_box(input[i]);
        }
    }

    function add_round_constants(Field.Type[4] memory state, Field.Type[4][64] memory round_constant, uint256 round)
        private
        pure
    {
        for (uint256 i; i < 4; i++) {
            state[i] = state[i].add(round_constant[round][i]);
        }
    }

    function matrix_multiplication_4x4(Field.Type[4] memory input) private pure {
        Field.Type t0 = input[0].add(input[1]); // A + B
        Field.Type t1 = input[2].add(input[3]); // C + D
        Field.Type t2 = input[1].add(input[1]); // 2B
        t2 = t2.add(t1); // 2B + C + D
        Field.Type t3 = input[3].add(input[3]); // 2D
        t3 = t3.add(t0); // 2D + A + B
        Field.Type t4 = t1.add(t1);
        t4 = t4.add(t4);
        t4 = t4.add(t3); // A + B + 4C + 6D
        Field.Type t5 = t0.add(t0);
        t5 = t5.add(t5);
        t5 = t5.add(t2); // 4A + 6B + C + D
        Field.Type t6 = t3.add(t5); // 5A + 7B + C + 3D
        Field.Type t7 = t2.add(t4); // A + 3B + 5C + 7D
        input[0] = t6;
        input[1] = t5;
        input[2] = t7;
        input[3] = t4;
    }

    function internal_m_multiplication(Field.Type[4] memory input, Field.Type[4] memory internal_matrix_diagonal)
        private
        pure
    {
        Field.Type sum = Field.Type.wrap(0);
        for (uint256 i; i < 4; i++) {
            sum = sum.add(input[i]);
        }
        for (uint256 i; i < 4; i++) {
            input[i] = input[i].mul(internal_matrix_diagonal[i]);
            input[i] = input[i].add(sum);
        }
    }

